    outputs = [Output(name="payload_out", display_name="선택된 페이로드", method="build_payload", types=["Data"])]

    def build_payload(self) -> Data:
        return Data(data=select_pandas_result(getattr(self, "original_payload", None), getattr(self, "retry_payload", None)))

from __future__ import annotations

import ast
import json
import re
import traceback
from copy import deepcopy
from datetime import date, datetime
from decimal import Decimal
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, MessageTextInput, Output
from lfx.schema.data import Data

FORBIDDEN_NAMES = {"open", "exec", "eval", "__import__", "compile", "input"}
RESULT_PREVIEW_LIMIT = 50
TRACE_PREVIEW_LIMIT = 5


def execute_pandas_code(payload_value: Any, llm_response: Any) -> dict[str, Any]:
    payload = _payload(payload_value)
    parsed = _json(llm_response)
    llm_code = str(parsed.get("code") or parsed.get("pandas_code") or "")
    code = llm_code
    next_payload = deepcopy(payload)
    if not code:
        return _analysis_error(next_payload, "missing_code", "pandas code LLM 응답에 code가 없습니다.", "")
    filter_plan = _pandas_filter_plan(next_payload)
    filter_preamble = _pandas_filter_preamble(filter_plan)
    code = _with_pandas_filter_preamble(code, filter_plan)
    helper_trace = _runtime_helper_trace(code)
    guard_error = _guard_code(code)
    if guard_error:
        return _analysis_error(next_payload, "unsafe_code", guard_error, code, "", llm_code, filter_preamble, filter_plan)
    try:
        import pandas as pd  # type: ignore

        source_columns_by_alias = _source_columns_by_alias(next_payload)
        sources = {}
        for alias, rows in next_payload.get("runtime_sources", {}).items():
            frame = pd.DataFrame(rows)
            if len(frame.columns) == 0:
                configured_columns = source_columns_by_alias.get(str(alias), [])
                if configured_columns:
                    frame = pd.DataFrame(columns=configured_columns)
            sources[alias] = frame
        safe_builtins = {
            "Exception": Exception,
            "all": all,
            "any": any,
            "bool": bool,
            "dict": dict,
            "enumerate": enumerate,
            "float": float,
            "hasattr": hasattr,
            "int": int,
            "isinstance": isinstance,
            "len": len,
            "list": list,
            "max": max,
            "min": min,
            "range": range,
            "round": round,
            "set": set,
            "sorted": sorted,
            "str": str,
            "sum": sum,
            "tuple": tuple,
        }
        step_outputs: list[dict[str, Any]] = []
        function_case_results: list[dict[str, Any]] = []

        def record_step(key: Any, value: Any, description: Any = "", role: Any = "") -> Any:
            step_outputs.append(_recorded_output(key, value, description, role))
            return value

        def record_function_case_result(function_name: Any, input_text: Any, result_value: Any, description: Any = "") -> Any:
            function_case_results.append(_recorded_function_case(function_name, input_text, result_value, description))
            return result_value

        exec_ns: dict[str, Any] = {
            "__builtins__": safe_builtins,
            "pd": pd,
            "sources": sources,
            "result": None,
            "result_df": None,
            "record_step": record_step,
            "record_function_case_result": record_function_case_result,
        }
        exec(compile(code, "<pandas_code>", "exec"), exec_ns, exec_ns)
        result = exec_ns.get("result")
        if result is None:
            result = exec_ns.get("result_df")
        rows, columns = _result_to_rows(result, next_payload)
        next_payload["_full_result_rows"] = rows
        next_payload["analysis"] = {
            "status": "ok",
            "row_count": len(rows),
            "columns": columns,
            "rows": rows[:RESULT_PREVIEW_LIMIT],
            "analysis_code": code,
            "llm_generated_code": llm_code,
            "pandas_filter_preamble": filter_preamble,
            "effective_code_with_helpers": helper_trace["effective_code_with_helpers"],
            "used_helpers": helper_trace["used_helpers"],
            "step_outputs": step_outputs,
            "function_case_results": function_case_results,
        }
        next_payload["data"] = {"columns": columns, "rows": rows[:RESULT_PREVIEW_LIMIT], "row_count": len(rows), "data_ref": ""}
        next_payload.setdefault("trace", {}).setdefault("inspection", {})["pandas_execution"] = {
            "stage": "17_pandas_code_executor",
            "status": "ok",
            "generated_code": code,
            "llm_generated_code": llm_code,
            "pandas_filter_preamble": filter_preamble,
            "effective_code_with_helpers": helper_trace["effective_code_with_helpers"],
            "used_helpers": helper_trace["used_helpers"],
            "helper_sources": helper_trace["helper_sources"],
            "pandas_filter_plan": filter_plan,
            "execution_result": {"row_count": len(rows), "columns": columns, "preview_rows": rows[:TRACE_PREVIEW_LIMIT]},
            "step_outputs": step_outputs,
            "function_case_results": function_case_results,
            "error": None,
        }
        return next_payload
    except Exception as exc:
        return _analysis_error(next_payload, "pandas_execution_error", f"{type(exc).__name__}: {exc}", code, traceback.format_exc(limit=3), llm_code, filter_preamble, filter_plan)


def _guard_code(code: str) -> str:
    try:
        tree = ast.parse(code)
    except SyntaxError as exc:
        return f"syntax error: {exc}"
    for node in ast.walk(tree):
        if isinstance(node, (ast.Import, ast.ImportFrom)):
            return "import 문은 허용하지 않습니다."
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Name) and node.func.id in FORBIDDEN_NAMES:
            return f"{node.func.id} 호출은 허용하지 않습니다."
        if isinstance(node, ast.Attribute) and node.attr.startswith("__"):
            return "dunder attribute 접근은 허용하지 않습니다."
    return ""


def _result_to_rows(result: Any, payload: dict[str, Any] | None = None) -> tuple[list[dict[str, Any]], list[str]]:
    if result is None:
        return [], []
    source_columns: list[str] = []
    if hasattr(result, "to_dict"):
        source_columns = [str(column) for column in getattr(result, "columns", [])]
        try:
            rows = result.to_dict(orient="records")
        except TypeError:
            converted = result.to_dict()
            rows = converted if isinstance(converted, list) else [converted]
    elif isinstance(result, list):
        rows = result
    elif isinstance(result, dict):
        rows = [result]
    else:
        row = _scalar_result_row(result, payload)
        return [row], list(row)
    rows = [_json_ready(row if isinstance(row, dict) else {"value": row}) for row in rows]
    if not rows and source_columns:
        return [], source_columns
    if len(rows) == 1 and len(rows[0]) == 1 and next(iter(rows[0].keys()), "") in {"result", "value"}:
        value = next(iter(rows[0].values()))
        row = _scalar_result_row(value, payload)
        return [row], list(row)
    columns = _ordered_columns(rows, source_columns)
    return rows, columns


def _ordered_columns(rows: list[dict[str, Any]], preferred: list[str] | None = None) -> list[str]:
    columns: list[str] = []
    for column in preferred or []:
        text = str(column)
        if text and text not in columns and any(text in row for row in rows):
            columns.append(text)
    for row in rows:
        if not isinstance(row, dict):
            continue
        for column in row:
            text = str(column)
            if text and text not in columns:
                columns.append(text)
    return columns


def _scalar_result_row(value: Any, payload: dict[str, Any] | None = None) -> dict[str, Any]:
    row = _scalar_context_row(payload)
    metric_label = _scalar_metric_label(payload)
    row[metric_label] = _json_ready(value)
    if len(row) == 1:
        return {"지표": metric_label, "값": _json_ready(value)}
    return row


def _scalar_context_row(payload: dict[str, Any] | None = None) -> dict[str, Any]:
    payload = payload if isinstance(payload, dict) else {}
    plan = payload.get("intent_plan") if isinstance(payload.get("intent_plan"), dict) else {}
    jobs = plan.get("retrieval_jobs") if isinstance(plan.get("retrieval_jobs"), list) else []
    row: dict[str, Any] = {}
    if not jobs:
        return row
    job = jobs[0] if isinstance(jobs[0], dict) else {}
    params = job.get("required_params") if isinstance(job.get("required_params"), dict) else {}
    filters = job.get("filters") if isinstance(job.get("filters"), dict) else {}
    date_value = params.get("DATE") or params.get("WORK_DATE") or params.get("date")
    if date_value not in (None, "", [], {}):
        row["기준일"] = _json_ready(date_value)
    for field, label in (
        ("OPER_NAME", "공정"),
        ("MCP_NO", "MCP NO"),
        ("DEVICE", "Device"),
    ):
        value = _filter_display_value(filters.get(field))
        if value not in (None, "", [], {}):
            row[label] = _json_ready(value)
    return row


def _filter_display_value(condition: Any) -> Any:
    if not isinstance(condition, dict):
        return condition
    if "value" in condition:
        return condition.get("value")
    if "values" in condition:
        values = condition.get("values")
        if isinstance(values, list):
            return ", ".join(str(value) for value in values)
        return values
    return condition


def _scalar_metric_label(payload: dict[str, Any] | None = None) -> str:
    payload = payload if isinstance(payload, dict) else {}
    request = payload.get("request") if isinstance(payload.get("request"), dict) else {}
    plan = payload.get("intent_plan") if isinstance(payload.get("intent_plan"), dict) else {}
    output_contract = plan.get("output_contract") if isinstance(plan.get("output_contract"), dict) else {}
    metric_name = str(output_contract.get("metric") or output_contract.get("measure") or output_contract.get("value_name") or "").strip()
    if metric_name:
        return metric_name
    text = " ".join(
        str(item or "")
        for item in (
            request.get("question"),
            plan.get("analysis_kind"),
            output_contract.get("description"),
            output_contract.get("title"),
        )
    ).upper()
    if any(token in text for token in ("INPUT", "투입")):
        return "INPUT 수량"
    if any(token in text for token in ("WIP", "재공")):
        return "재공 수량"
    if any(token in text for token in ("PRODUCTION", "OUTPUT", "OUT", "생산", "실적")):
        return "생산 실적"
    return "결과값"


def _recorded_output(key: Any, value: Any, description: Any = "", role: Any = "") -> dict[str, Any]:
    rows, columns, row_count = _preview_rows_columns_count(value)
    return _json_ready(
        {
            "key": str(key or ""),
            "description": str(description or ""),
            "role": str(role or ""),
            "row_count": row_count,
            "columns": columns,
            "preview_rows": rows[:TRACE_PREVIEW_LIMIT],
        }
    )


def _recorded_function_case(function_name: Any, input_text: Any, result_value: Any, description: Any = "") -> dict[str, Any]:
    rows, columns, row_count = _preview_rows_columns_count(result_value)
    return _json_ready(
        {
            "function_name": str(function_name or ""),
            "input_text": str(input_text or ""),
            "description": str(description or ""),
            "matched_count": row_count,
            "columns": columns,
            "preview_rows": rows[:TRACE_PREVIEW_LIMIT],
        }
    )


def _preview_rows_columns_count(value: Any) -> tuple[list[dict[str, Any]], list[str], int]:
    if hasattr(value, "head") and hasattr(value, "to_dict"):
        try:
            row_count = len(value)
        except Exception:
            row_count = 0
        try:
            preview_value = value.head(TRACE_PREVIEW_LIMIT)
            rows = preview_value.to_dict(orient="records")
            columns = [str(column) for column in getattr(value, "columns", [])]
            if not columns:
                columns = sorted({column for row in rows for column in row})
            return [_json_ready(row if isinstance(row, dict) else {"value": row}) for row in rows], columns, int(row_count)
        except Exception:
            pass
    rows, columns = _result_to_rows(value)
    return rows[:TRACE_PREVIEW_LIMIT], columns, len(rows)


def _json_ready(value: Any) -> Any:
    if value is None or type(value) in (str, int, bool):
        return value
    if type(value) is float:
        return None if value != value or value in (float("inf"), -float("inf")) else value
    if isinstance(value, (datetime, date)):
        return value.isoformat()
    if isinstance(value, Decimal):
        return float(value)
    item = getattr(value, "item", None)
    if callable(item):
        try:
            return _json_ready(item())
        except Exception:
            pass
    if isinstance(value, dict):
        return {str(key): _json_ready(item_value) for key, item_value in value.items()}
    if isinstance(value, (list, tuple, set)):
        return [_json_ready(item_value) for item_value in value]
    try:
        if value != value:
            return None
    except Exception:
        pass
    return str(value)


def _analysis_error(
    payload: dict[str, Any],
    error_type: str,
    message: str,
    code: str,
    tb: str = "",
    llm_code: str = "",
    filter_preamble: str = "",
    filter_plan: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    helper_trace = _runtime_helper_trace(code)
    payload["analysis"] = {
        "status": "error",
        "row_count": 0,
        "columns": [],
        "rows": [],
        "error": {"type": error_type, "message": message},
        "errors": [message],
        "repairable_errors": [message],
        "analysis_code": code,
        "llm_generated_code": llm_code or code,
        "pandas_filter_preamble": filter_preamble,
        "effective_code_with_helpers": helper_trace["effective_code_with_helpers"],
        "used_helpers": helper_trace["used_helpers"],
        "step_outputs": [],
        "function_case_results": [],
    }
    payload.setdefault("trace", {}).setdefault("errors", []).append({"type": error_type, "message": message})
    payload.setdefault("trace", {}).setdefault("inspection", {})["pandas_execution"] = {
        "stage": "17_pandas_code_executor",
        "status": "error",
        "generated_code": code,
        "llm_generated_code": llm_code or code,
        "pandas_filter_preamble": filter_preamble,
        "pandas_filter_plan": filter_plan or [],
        "effective_code_with_helpers": helper_trace["effective_code_with_helpers"],
        "used_helpers": helper_trace["used_helpers"],
        "helper_sources": helper_trace["helper_sources"],
        "step_outputs": [],
        "function_case_results": [],
        "error": {"type": error_type, "message": message, "traceback_summary": tb[:1000]},
    }
    return payload


def _runtime_helper_trace(code: str) -> dict[str, Any]:
    helper_names = _used_inline_helpers(code)
    return {
        "used_helpers": helper_names,
        "helper_sources": [],
        "effective_code_with_helpers": str(code or "").strip(),
    }


def _used_inline_helpers(code: str) -> list[str]:
    try:
        tree = ast.parse(code or "")
    except SyntaxError:
        return []
    instrumentation_functions = {"record_step", "record_function_case_result"}
    top_level_functions = [
        node.name
        for node in tree.body
        if isinstance(node, ast.FunctionDef) and not node.name.startswith("_") and node.name not in instrumentation_functions
    ]
    used: list[str] = []
    for node in ast.walk(tree):
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Name) and node.func.id in top_level_functions:
            if node.func.id not in used:
                used.append(node.func.id)
    return used


def _as_list(value: Any) -> list[Any]:
    if isinstance(value, list):
        return value
    if isinstance(value, tuple):
        return list(value)
    if value in (None, "", {}, []):
        return []
    return [value]


def _pandas_filter_plan(payload: dict[str, Any]) -> list[dict[str, Any]]:
    plan = payload.get("intent_plan") if isinstance(payload.get("intent_plan"), dict) else {}
    jobs = plan.get("retrieval_jobs") if isinstance(plan.get("retrieval_jobs"), list) else []
    filter_plan: list[dict[str, Any]] = []
    for job in jobs:
        if not isinstance(job, dict):
            continue
        alias = str(job.get("source_alias") or job.get("dataset_key") or "").strip()
        if not alias:
            continue
        conditions = _filter_conditions(job.get("filters"))
        if conditions:
            filter_plan.append({"source_alias": alias, "dataset_key": job.get("dataset_key", ""), "conditions": conditions})
    return filter_plan


def _with_pandas_filter_preamble(code: Any, filter_plan: list[dict[str, Any]]) -> str:
    base_code = str(code or "").strip()
    preamble = _pandas_filter_preamble(filter_plan)
    if not preamble:
        return base_code
    return preamble + "\n\n" + base_code


def _pandas_filter_preamble(filter_plan: list[dict[str, Any]]) -> str:
    lines: list[str] = []
    for job_index, item in enumerate(filter_plan, start=1):
        alias = str(item.get("source_alias") or "").strip()
        conditions = item.get("conditions") if isinstance(item.get("conditions"), list) else []
        if not alias or not conditions:
            continue
        df_var = f"_filtered_source_{job_index}_{_safe_name(alias)}"
        lines.append(f"{df_var} = sources.get({alias!r})")
        lines.append(f"if {df_var} is not None:")
        lines.append("    sources = dict(sources)")
        lines.append(f"    {df_var} = {df_var}.copy()")
        for condition_index, condition in enumerate(conditions, start=1):
            lines.extend(_condition_code(df_var, job_index, condition_index, condition))
        lines.append(f"    sources[{alias!r}] = {df_var}")
    return "\n".join(lines)


def _condition_code(df_var: str, job_index: int, condition_index: int, condition: dict[str, Any]) -> list[str]:
    field = str(condition.get("field") or "").strip()
    operator = _normalize_filter_operator(condition.get("operator") or "eq")
    values = condition.get("values") if isinstance(condition.get("values"), list) else []
    if not field or (not values and operator not in {"is_null", "is_empty", "null_or_empty", "not_null", "not_empty"}):
        return []
    col_var = f"_filter_col_{job_index}_{condition_index}"
    values_var = f"_filter_values_{job_index}_{condition_index}"
    mask_var = f"_filter_mask_{job_index}_{condition_index}"
    candidates = _field_candidates(field)
    lines = [f"    {col_var} = {_column_choice_expression(df_var, candidates)}", f"    {values_var} = {values!r}", f"    if {col_var}:"]
    if operator in {"eq", "in"}:
        lines.append(f"        {df_var} = {df_var}[{df_var}[{col_var}].isin({values_var})]")
    elif operator in {"ne", "not_in"}:
        lines.append(f"        {df_var} = {df_var}[~{df_var}[{col_var}].isin({values_var})]")
    elif operator in {"contains", "like"}:
        lines.append(f"        {mask_var} = {df_var}[{col_var}].astype(str).str.contains(str({values_var}[0]), case=False, na=False, regex=False)")
        lines.append(f"        for _filter_value in {values_var}[1:]:")
        lines.append(f"            {mask_var} = {mask_var} | {df_var}[{col_var}].astype(str).str.contains(str(_filter_value), case=False, na=False, regex=False)")
        lines.append(f"        {df_var} = {df_var}[{mask_var}]")
    elif operator in {"starts_with", "startswith", "prefix"}:
        lines.append(f"        {mask_var} = {df_var}[{col_var}].astype(str).str.startswith(str({values_var}[0]), na=False)")
        lines.append(f"        for _filter_value in {values_var}[1:]:")
        lines.append(f"            {mask_var} = {mask_var} | {df_var}[{col_var}].astype(str).str.startswith(str(_filter_value), na=False)")
        lines.append(f"        {df_var} = {df_var}[{mask_var}]")
    elif operator in {"ends_with", "endswith", "suffix"}:
        lines.append(f"        {mask_var} = {df_var}[{col_var}].astype(str).str.endswith(str({values_var}[0]), na=False)")
        lines.append(f"        for _filter_value in {values_var}[1:]:")
        lines.append(f"            {mask_var} = {mask_var} | {df_var}[{col_var}].astype(str).str.endswith(str(_filter_value), na=False)")
        lines.append(f"        {df_var} = {df_var}[{mask_var}]")
    elif operator in {"is_null", "is_empty", "null_or_empty", "not_null", "not_empty"}:
        lines.extend(_null_empty_condition_lines(df_var, col_var, mask_var, operator))
    elif operator in {"or", "any"} and _has_operator_dict(values):
        lines.extend(_compound_condition_lines(df_var, col_var, mask_var, values))
    else:
        lines.append("        pass")
    return lines


def _normalize_filter_operator(value: Any) -> str:
    text = re.sub(r"[\s-]+", "_", str(value or "eq").strip()).lower()
    aliases = {
        "=": "eq",
        "==": "eq",
        "!=": "ne",
        "not in": "not_in",
        "notin": "not_in",
        "starts": "starts_with",
        "startwith": "starts_with",
        "startswith": "starts_with",
        "starts_with_any": "starts_with",
        "prefix": "starts_with",
        "endswith": "ends_with",
        "suffix": "ends_with",
        "isnull": "is_null",
        "is_null": "is_null",
        "null": "is_null",
        "none": "is_null",
        "isempty": "is_empty",
        "is_empty": "is_empty",
        "empty": "is_empty",
        "blank": "is_empty",
        "null_or_empty": "null_or_empty",
        "is_null_or_empty": "null_or_empty",
        "notnull": "not_null",
        "not_null": "not_null",
        "notempty": "not_empty",
        "not_empty": "not_empty",
        "any": "any",
        "or": "or",
    }
    return aliases.get(text, text)


def _null_empty_condition_lines(df_var: str, col_var: str, mask_var: str, operator: str) -> list[str]:
    series = f"{df_var}[{col_var}]"
    if operator == "is_null":
        return [f"        {df_var} = {df_var}[{series}.isna()]"]
    if operator == "is_empty":
        return [f"        {df_var} = {df_var}[{series}.astype(str).str.strip().eq('')]"]
    if operator == "null_or_empty":
        return [f"        {mask_var} = {series}.isna() | {series}.astype(str).str.strip().eq('')", f"        {df_var} = {df_var}[{mask_var}]"]
    if operator == "not_null":
        return [f"        {df_var} = {df_var}[{series}.notna()]"]
    if operator == "not_empty":
        return [f"        {df_var} = {df_var}[~{series}.astype(str).str.strip().eq('')]"]
    return ["        pass"]


def _has_operator_dict(values: list[Any]) -> bool:
    return any(isinstance(item, dict) and (item.get("operator") or item.get("op")) for item in values)


def _compound_condition_lines(df_var: str, col_var: str, mask_var: str, values: list[Any]) -> list[str]:
    series = f"{df_var}[{col_var}]"
    lines = [f"        {mask_var} = False"]
    for item in values:
        if not isinstance(item, dict):
            continue
        op = _normalize_filter_operator(item.get("operator") or item.get("op") or "eq")
        raw_values = _as_values(item.get("values", item.get("value", [])))
        if op == "is_null":
            lines.append(f"        {mask_var} = {mask_var} | {series}.isna()")
        elif op == "is_empty":
            lines.append(f"        {mask_var} = {mask_var} | {series}.astype(str).str.strip().eq('')")
        elif op == "null_or_empty":
            lines.append(f"        {mask_var} = {mask_var} | {series}.isna() | {series}.astype(str).str.strip().eq('')")
        elif op in {"eq", "in"} and raw_values:
            lines.append(f"        {mask_var} = {mask_var} | {series}.isin({raw_values!r})")
        elif op == "starts_with" and raw_values:
            lines.append(f"        {mask_var} = {mask_var} | {series}.astype(str).str.startswith(str({raw_values[0]!r}), na=False)")
            for raw_value in raw_values[1:]:
                lines.append(f"        {mask_var} = {mask_var} | {series}.astype(str).str.startswith(str({raw_value!r}), na=False)")
        elif op in {"contains", "like"} and raw_values:
            lines.append(f"        {mask_var} = {mask_var} | {series}.astype(str).str.contains(str({raw_values[0]!r}), case=False, na=False, regex=False)")
            for raw_value in raw_values[1:]:
                lines.append(f"        {mask_var} = {mask_var} | {series}.astype(str).str.contains(str({raw_value!r}), case=False, na=False, regex=False)")
    lines.append(f"        {df_var} = {df_var}[{mask_var}]")
    return lines


def _column_choice_expression(df_var: str, candidates: list[str]) -> str:
    expression = "''"
    for candidate in reversed(candidates):
        expression = f"{candidate!r} if {candidate!r} in {df_var}.columns else ({expression})"
    return expression


def _filter_conditions(filters: Any) -> list[dict[str, Any]]:
    if isinstance(filters, list):
        items = [(condition.get("field") or condition.get("column"), condition) for condition in filters if isinstance(condition, dict)]
    elif isinstance(filters, dict):
        items = list(filters.items())
    else:
        return []
    result: list[dict[str, Any]] = []
    for field, condition in items:
        field_text = str(field or "").strip()
        if not field_text:
            continue
        if isinstance(condition, dict):
            operator = condition.get("operator", condition.get("op", "eq"))
            values = condition.get("values", condition.get("value", []))
        elif isinstance(condition, list) and _has_operator_dict(condition):
            operator = "or"
            values = condition
        else:
            operator = "eq"
            values = condition
        normalized_values = _as_values(values)
        normalized_operator = _normalize_filter_operator(operator or "eq")
        if normalized_values or normalized_operator in {"is_null", "is_empty", "null_or_empty", "not_null", "not_empty"}:
            result.append({"field": field_text, "operator": normalized_operator, "values": normalized_values})
    return result


def _as_values(value: Any) -> list[Any]:
    if isinstance(value, list):
        return [item for item in value if item not in (None, "")]
    if isinstance(value, tuple):
        return [item for item in value if item not in (None, "")]
    if value in (None, ""):
        return []
    return [value]


def _field_candidates(field: str) -> list[str]:
    aliases = {
        "DATE": ["DATE", "WORK_DATE", "WORK_DT", "LOAD_DT", "BASE_DT"],
        "WORK_DATE": ["WORK_DATE", "WORK_DT", "DATE"],
        "MODE": ["MODE", "Mode"],
        "DEN": ["DEN", "DENSITY"],
        "PKG_TYPE1": ["PKG_TYPE1", "PKG1"],
        "PKG_TYPE2": ["PKG_TYPE2", "PKG2"],
        "MCP_NO": ["MCP_NO", "MCP NO"],
        "TSV_DIE_TYP": ["TSV_DIE_TYP", "TSV_DIE_TYPE"],
        "OPER_NUM": ["OPER_NUM", "OPER"],
        "OPER_NAME": ["OPER_NAME", "OPER_NM"],
        "EQP_ID": ["EQP_ID", "EQUIP_ID"],
        "EQP_MODEL": ["EQP_MODEL", "EQUIP_MODEL", "EQPIP_MODEL"],
    }
    return aliases.get(field, [field])


def _safe_name(value: str) -> str:
    cleaned = re.sub(r"\W+", "_", value)
    return cleaned.strip("_") or "source"


def _payload(value: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    return deepcopy(data) if isinstance(data, dict) else {}


def _source_columns_by_alias(payload: dict[str, Any]) -> dict[str, list[str]]:
    result: dict[str, list[str]] = {}
    for source in payload.get("source_results", []) if isinstance(payload.get("source_results"), list) else []:
        if not isinstance(source, dict):
            continue
        alias = str(source.get("source_alias") or source.get("dataset_key") or "").strip()
        columns = _string_list(source.get("columns"))
        if alias and columns:
            result[alias] = columns
    return result


def _string_list(value: Any) -> list[str]:
    return [str(item) for item in value if str(item or "").strip()] if isinstance(value, list) else []


def _json(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return deepcopy(value)
    text = _text_value(value)
    match = re.search(r"```(?:json)?\s*(.*?)\s*```", text, re.DOTALL)
    if match:
        text = match.group(1).strip()
    elif "{" in text and "}" in text:
        text = text[text.find("{") : text.rfind("}") + 1]
    try:
        parsed = json.loads(text)
    except Exception:
        try:
            parsed = json.loads(text, strict=False)
        except Exception:
            return {}
    return parsed if isinstance(parsed, dict) else {}


def _text_value(value: Any) -> str:
    for attr in ("text", "content", "message"):
        text = getattr(value, attr, None)
        if isinstance(text, str):
            return text
    data = getattr(value, "data", None)
    if isinstance(data, dict):
        for key in ("text", "content", "message", "output"):
            if isinstance(data.get(key), str):
                return data[key]
    return str(value or "")


class PandasCodeExecutor(Component):
    display_name = "17 pandas 코드 실행기"
    description = "Langflow 에이전트/LLM이 반환한 pandas JSON 코드를 안전 검사 후 실행합니다."
    inputs = [DataInput(name="payload", display_name="페이로드", required=True), MessageTextInput(name="llm_response", display_name="pandas 코드 LLM 응답", required=True)]
    outputs = [Output(name="payload_out", display_name="페이로드 출력", method="build_payload")]

    def build_payload(self) -> Data:
        return Data(data=execute_pandas_code(getattr(self, "payload", None), getattr(self, "llm_response", "")))

from __future__ import annotations

import re
from copy import deepcopy
from datetime import datetime, timedelta
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, Output
from lfx.schema.data import Data

FOLLOWUP_REFERENCE_CUES = (
    "그", "이전", "방금", "위", "아까", "저 결과", "결과에서", "표에서", "여기서", "거기서",
    "같은 조건", "동일 조건", "그 제품", "그 공정", "해당 제품", "해당 공정",
)
EXPLAIN_CUES = ("왜", "이유", "근거", "설명", "어떤 조건", "어떤 데이터", "조회 조건", "pandas", "코드")
TRANSFORM_CUES = ("상위", "하위", "정렬", "나눠", "분리", "제품별", "공정별", "차수별", "세부", "비율", "rank", "top", "bottom")
EXPAND_CUES = ("추가", "넣어", "붙여", "포함", "같이", "함께", "컬럼", "열", "항목", "code", "코드", "번호")
CHANGE_CUES = ("말고", "대신", "아니", "바꿔", "변경", "다른", "새로", "다시 조회", "재조회")
DATE_CUE_PATTERN = re.compile(r"(\b\d{1,2}/\d{1,2}\b|\b\d{1,2}월\s*\d{1,2}일\b|오늘|금일|어제|전일|내일|현시간|현재)")


def build_followup_hint(payload_value: Any) -> dict[str, Any]:
    payload = _payload(payload_value)
    question = str(_dict(payload.get("request")).get("question") or "").strip()
    state = _dict(payload.get("state"))
    previous_context = _previous_context(state)
    has_previous = bool(previous_context.get("has_previous_context"))

    date_hint = _date_change_hint(question, _dict(payload.get("request")).get("reference_date"))
    matched_references = _matched_cues(question, FOLLOWUP_REFERENCE_CUES)
    matched_explain = _matched_cues(question, EXPLAIN_CUES)
    matched_transform = _matched_cues(question, TRANSFORM_CUES)
    matched_expand = _matched_cues(question, EXPAND_CUES)
    matched_change = _matched_cues(question, CHANGE_CUES)
    requested_columns = _matched_previous_columns(question, _available_previous_columns(state), matched_expand)
    context_dependent = _looks_context_dependent(question)

    scope_hint = "new_analysis"
    reuse_strategy_hint = "none"
    confidence = "low"
    required_artifacts: list[str] = []
    inheritance_candidates: list[str] = []

    if has_previous:
        if matched_explain and (matched_references or context_dependent):
            scope_hint = "followup_explain"
            reuse_strategy_hint = "trace_only"
            confidence = "medium" if matched_references else "low"
            required_artifacts = ["previous_trace", "previous_intent_plan", "previous_answer"]
        elif requested_columns or (matched_expand and (matched_references or context_dependent)):
            scope_hint = "followup_expand_source"
            reuse_strategy_hint = "previous_source"
            confidence = "high" if requested_columns or matched_references else "medium"
            required_artifacts = ["previous_source", "previous_result", "previous_intent_plan"]
            inheritance_candidates = ["metric", "required_params", "analysis_filters", "group_by", "pandas_function_cases"]
        elif matched_change or (date_hint and (matched_references or context_dependent)):
            scope_hint = "followup_requery"
            reuse_strategy_hint = "previous_intent_with_new_retrieval"
            confidence = "high" if matched_references or _looks_context_dependent(question) else "medium"
            required_artifacts = ["previous_intent_plan", "previous_applied_criteria"]
            inheritance_candidates = ["metric", "analysis_filters", "group_by", "pandas_function_cases", "output_contract"]
        elif matched_transform and (matched_references or context_dependent):
            scope_hint = "followup_transform"
            reuse_strategy_hint = "previous_result"
            confidence = "high" if matched_references else "medium"
            required_artifacts = ["previous_result", "previous_source", "previous_intent_plan"]
            inheritance_candidates = ["required_params", "analysis_filters", "pandas_function_cases"]
        elif matched_references:
            scope_hint = "followup_requery"
            reuse_strategy_hint = "previous_intent_with_new_retrieval"
            confidence = "medium"
            required_artifacts = ["previous_result", "previous_intent_plan", "previous_applied_criteria"]
            inheritance_candidates = ["metric", "required_params", "analysis_filters", "group_by", "pandas_function_cases"]

    hint = _omit_empty(
        {
            "followup_candidate": scope_hint != "new_analysis",
            "request_scope_hint": scope_hint,
            "reuse_strategy_hint": reuse_strategy_hint,
            "confidence": confidence,
            "changed_conditions_hint": _omit_empty({"date": date_hint}) if date_hint else {},
            "matched_cues": _omit_empty(
                {
                    "reference": matched_references,
                    "explain": matched_explain,
                    "transform": matched_transform,
                    "expand": matched_expand,
                    "change": matched_change,
                }
            ),
            "requested_columns_hint": requested_columns,
            "required_previous_artifacts": required_artifacts,
            "inheritance_candidates": inheritance_candidates,
            "previous_context": previous_context,
            "notes": _notes(scope_hint, reuse_strategy_hint, requested_columns, date_hint),
        }
    )
    next_payload = deepcopy(payload)
    next_payload["followup_hint"] = hint
    next_payload.setdefault("trace", {}).setdefault("inspection", {})["followup_hint"] = {
        "stage": "01e_followup_hint_builder",
        **hint,
    }
    return next_payload


def _previous_context(state: dict[str, Any]) -> dict[str, Any]:
    current_data = _dict(state.get("current_data"))
    last_intent = _dict(state.get("last_intent_plan"))
    last_applied = _dict(state.get("last_applied_criteria"))
    source_columns = _compact_source_columns(current_data.get("source_columns_by_alias"))
    columns = _string_list(current_data.get("columns")) or _string_list(current_data.get("result_columns"))
    return _omit_empty(
        {
            "has_previous_context": bool(current_data or last_intent or last_applied or state.get("last_question")),
            "last_question": state.get("last_question") or _dict(state.get("request")).get("question"),
            "last_answer_message": _clip_text(state.get("last_answer_message"), 700),
            "current_data": _omit_empty(
                {
                    "row_count": current_data.get("row_count"),
                    "columns": columns[:60],
                    "data_ref": current_data.get("data_ref"),
                    "source_aliases": _string_list(current_data.get("source_aliases"))[:20],
                    "source_dataset_keys": _string_list(current_data.get("source_dataset_keys"))[:20],
                    "source_columns_by_alias": source_columns,
                }
            ),
            "last_intent_plan": _compact_intent_plan(last_intent),
            "last_applied_criteria": _compact_applied_criteria(last_applied),
        }
    )


def _compact_intent_plan(plan: dict[str, Any]) -> dict[str, Any]:
    return _omit_empty(
        {
            "analysis_kind": plan.get("analysis_kind"),
            "retrieval_jobs": _compact_retrieval_jobs(_list(plan.get("retrieval_jobs"))),
            "pandas_execution_plan": deepcopy(_list(plan.get("pandas_execution_plan"))[:8]),
            "pandas_function_cases": deepcopy(_list(plan.get("pandas_function_cases"))[:5]),
            "output_contract": deepcopy(_dict(plan.get("output_contract"))),
        }
    )


def _compact_retrieval_jobs(jobs: list[Any]) -> list[dict[str, Any]]:
    result = []
    for job in jobs:
        if not isinstance(job, dict):
            continue
        result.append(
            _omit_empty(
                {
                    "dataset_key": job.get("dataset_key"),
                    "source_alias": job.get("source_alias"),
                    "source_type": job.get("source_type"),
                    "required_params": deepcopy(job.get("required_params")),
                    "filters": deepcopy(job.get("filters")),
                }
            )
        )
    return result


def _compact_applied_criteria(criteria: dict[str, Any]) -> dict[str, Any]:
    return _omit_empty(
        {
            "required_params": deepcopy(_dict(criteria.get("required_params"))),
            "analysis_filters": deepcopy(_dict(criteria.get("analysis_filters"))),
            "retrieval_filters": deepcopy(_dict(criteria.get("retrieval_filters"))),
            "group_by": _string_list(criteria.get("group_by")),
            "metrics": _string_list(criteria.get("metrics")),
            "datasets": deepcopy(_list(criteria.get("datasets"))[:10]),
        }
    )


def _date_change_hint(question: str, reference_date: Any) -> dict[str, Any]:
    text = str(question or "")
    if not DATE_CUE_PATTERN.search(text):
        return {}
    ref_date = _parse_reference_date(reference_date)
    date_value = ""
    if "어제" in text or "전일" in text:
        date_value = (ref_date - timedelta(days=1)).strftime("%Y%m%d") if ref_date else "yesterday"
    elif "오늘" in text or "금일" in text or "현시간" in text or "현재" in text:
        date_value = ref_date.strftime("%Y%m%d") if ref_date else "today"
    elif "내일" in text:
        date_value = (ref_date + timedelta(days=1)).strftime("%Y%m%d") if ref_date else "tomorrow"
    explicit = _explicit_date(text, ref_date)
    if explicit:
        date_value = explicit
    return _omit_empty({"expression": _date_expression(text), "resolved_value": date_value})


def _explicit_date(text: str, ref_date: datetime | None) -> str:
    slash = re.search(r"\b(\d{1,2})/(\d{1,2})\b", text)
    korean = re.search(r"\b(\d{1,2})월\s*(\d{1,2})일\b", text)
    match = slash or korean
    if not match:
        return ""
    year = ref_date.year if ref_date else datetime.now().year
    month = int(match.group(1))
    day = int(match.group(2))
    try:
        return datetime(year, month, day).strftime("%Y%m%d")
    except Exception:
        return ""


def _date_expression(text: str) -> str:
    match = DATE_CUE_PATTERN.search(text)
    return match.group(0) if match else ""


def _parse_reference_date(value: Any) -> datetime | None:
    text = str(value or "").strip()
    try:
        return datetime.strptime(text, "%Y%m%d")
    except Exception:
        return None


def _matched_previous_columns(question: str, columns: list[str], expand_cues: list[str]) -> list[str]:
    if not columns or not expand_cues:
        return []
    normalized_question = _normalize(question)
    result = []
    for column in columns:
        if any(_normalize(alias) in normalized_question for alias in _column_aliases(column)):
            result.append(column)
    return result


def _available_previous_columns(state: dict[str, Any]) -> list[str]:
    current_data = _dict(state.get("current_data"))
    columns: list[str] = []
    _extend_unique(columns, _string_list(current_data.get("columns")))
    _extend_unique(columns, _string_list(current_data.get("result_columns")))
    source_columns = current_data.get("source_columns_by_alias")
    if isinstance(source_columns, dict):
        for value in source_columns.values():
            _extend_unique(columns, _string_list(value))
    for source in _list(state.get("followup_source_results")):
        if isinstance(source, dict):
            _extend_unique(columns, _string_list(source.get("columns")))
    return columns


def _column_aliases(column: str) -> list[str]:
    raw = str(column or "").strip()
    if not raw:
        return []
    aliases = {raw, raw.replace("_", " "), raw.replace("_", "-")}
    upper = raw.upper()
    for suffix in ("_NO", "_CODE", "_CD", "_ID"):
        if upper.endswith(suffix):
            base = raw[: -len(suffix)].strip("_- ")
            if base:
                aliases.update({base, f"{base} no", f"{base} number", f"{base} code", f"{base} 코드", f"{base} 번호"})
    return sorted(aliases, key=len, reverse=True)


def _looks_context_dependent(question: str) -> bool:
    text = str(question or "")
    compact = re.sub(r"\s+", "", text)
    if any(token in text.lower() for token in ("공정", "제품", "장비", "lot", "device", "데이터셋", "dataset")):
        return False
    return len(compact) <= 18


def _matched_cues(question: str, cues: tuple[str, ...]) -> list[str]:
    normalized_question = _normalize(question)
    return [cue for cue in cues if _normalize(cue) in normalized_question]


def _notes(scope_hint: str, reuse_strategy: str, requested_columns: list[str], date_hint: dict[str, Any]) -> list[str]:
    notes = []
    if scope_hint == "new_analysis":
        notes.append("독립 질문으로 보이며 이전 조건 상속은 필수로 판단하지 않았습니다.")
    else:
        notes.append("후속 질문 가능성이 있으므로 이전 조건의 상속/변경 여부를 의도 분석에서 최종 판단해야 합니다.")
    if reuse_strategy == "previous_intent_with_new_retrieval":
        notes.append("이전 intent의 metric/filter/group 조건을 검토하고, 변경 조건이 required_params에 영향을 주면 새 조회를 생성합니다.")
    if reuse_strategy == "previous_source":
